A character class replicating health and executing a server attack RPC:

```cpp
#include

UCLASS()
class AReplicatedCharacter : public ACharacter {
    GENERATED_BODY()

public:
    // Replicated specifier registers variable with Net Driver replication sweeps
    UPROPERTY(ReplicatedUsing = OnRep_Health)
    float Health = 100.0f;

    UFUNCTION()
    void OnRep_Health() {
        // Trigger visual updates on clients when health changes
    }

    // Server RPC declaration (With validation check to block cheat inputs)
    UFUNCTION(Server, Reliable, WithValidation)
    void ServerAttack(AActor* Target);
};

void AReplicatedCharacter::GetLifetimeReplicatedProps(TArray<FLifetimeProperty>& OutLifetimeProps) const {
    Super::GetLifetimeReplicatedProps(OutLifetimeProps);
    DOREPLIFETIME(AReplicatedCharacter, Health); // Register Health variable
}
```
